async (page) => {
  const fs = require('fs');

  const files = [
    'C:\\Users\\33908\\Desktop\\AI大模型（AIGC）赋能企业创新.docx',
    'C:\\Users\\33908\\Desktop\\交接文档.docx',
    'C:\\Users\\33908\\Desktop\\演讲稿.docx',
    'C:\\Users\\33908\\Desktop\\建筑AI课程.docx'
  ];

  const results = {};

  for (const filePath of files) {
    try {
      const buffer = fs.readFileSync(filePath);
      const text = buffer.toString('utf-8');
      // Extract text between <w:t> tags (docx XML structure)
      const matches = text.match(/<w:t[^>]*>([^<]+)<\/w:t>/g) || [];
      const extractedText = matches.map(m => m.replace(/<[^>]+>/g, '')).join('');
      results[filePath] = extractedText.substring(0, 3000);
    } catch (e) {
      results[filePath] = 'ERROR: ' + e.message;
    }
  }

  return JSON.stringify(results, null, 2);
}

import zipfile
import re
import os

files = [
    r"C:\Users\33908\Desktop\AI大模型（AIGC）赋能企业创新.docx",
    r"C:\Users\33908\Desktop\交接文档.docx",
    r"C:\Users\33908\Desktop\演讲稿.docx",
    r"C:\Users\33908\Desktop\建筑AI课程.docx"
]

results = {}

for fp in files:
    try:
        name = os.path.basename(fp)
        exists = os.path.exists(fp)
        if not exists:
            results[name] = {"exists": False}
            continue
        with zipfile.ZipFile(fp, 'r') as z:
            with z.open('word/document.xml') as f:
                content = f.read().decode('utf-8', errors='ignore')
                # Extract text from <w:t> tags
                texts = re.findall(r'<w:t[^>]*>([^<]+)</w:t>', content)
                full_text = ''.join(texts)
                # Get first 2000 chars
                results[name] = {
                    "exists": True,
                    "length": len(full_text),
                    "preview": full_text[:2000]
                }
    except Exception as e:
        results[os.path.basename(fp)] = {"error": str(e)}

import json
print(json.dumps(results, ensure_ascii=False, indent=2))

